import React, { useEffect, useState } from "react";

const textOptions = ["React.js", "React Native", "Full Stack Development"];

export default function Intro() {
  const [currentText, setCurrentText] = useState("");
  const [textIndex, setTextIndex] = useState(0);
  const [charIndex, setCharIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    const currentString = textOptions[textIndex];
    const timeout = setTimeout(() => {
      setCurrentText(currentString.substring(0, charIndex + (isDeleting ? -1 : 1)));
      setCharIndex(charIndex + (isDeleting ? -1 : 1));

      if (!isDeleting && charIndex === currentString.length) {
        setIsDeleting(true);
      } else if (isDeleting && charIndex === 0) {
        setIsDeleting(false);
        setTextIndex((textIndex + 1) % textOptions.length);
      }
    }, isDeleting ? 50 : 150);

    return () => clearTimeout(timeout);
  }, [charIndex, isDeleting, textIndex]);

  return (
    <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "20px", textAlign: "center", color: "#fff", backgroundColor: "#191919" }}>
      <div style={{ position: "fixed", left: "20px", top: "50%", transform: "translateY(-50%)", display: "flex", flexDirection: "column", gap: "16px" }}>
        <a href="#" style={{ fontSize: "20px", color: "#fff", textDecoration: "none" }}><i className="fa-brands fa-github"></i></a>
        <a href="#" style={{ fontSize: "20px", color: "#fff", textDecoration: "none" }}><i className="fa-brands fa-discord"></i></a>
        <a href="#" style={{ fontSize: "20px", color: "#fff", textDecoration: "none" }}><i className="fa-brands fa-twitter"></i></a>
      </div>
      <div style={{ fontSize: "32px", fontWeight: "bold", marginBottom: "20px" }}>
        Elias is a <span style={{ color: "#c778dd" }}>web designer</span> and<br />
        <span style={{ color: "#c778dd" }}>front-end developer</span>
      </div>
      <p style={{ color: "#abb2bf" }}>He crafts responsive websites where technologies meet creativity</p>
      <button style={{ background: "transparent", color: "#fff", border: "1px solid #c778dd", padding: "8px 16px", cursor: "pointer", fontFamily: "'Fira Code', monospace", transition: "background-color 0.3s" }}>Contact me !!</button>
      <div style={{ marginTop: "20px", position: "relative" }}>
        <img src="assets/header_img.png" alt="Elias in a hoodie" style={{ width: "200px", borderRadius: "10px" }} />
        <div style={{ position: "absolute", bottom: "10px", left: "10px", backgroundColor: "#191919", border: "1px solid #c778dd", padding: "8px", display: "flex", alignItems: "center", gap: "8px" }}>
          <div style={{ width: "12px", height: "12px", backgroundColor: "#c778dd", borderRadius: "50%" }}></div>
          <p style={{ margin: 0 }}>Currently working on <span style={{ fontWeight: "bold" }}>Portfolio</span></p>
        </div>
      </div>
      <p style={{ marginTop: "20px", fontSize: "24px", color: "#c778dd" }}>{currentText}</p>
    </div>
  );
}
